128	export type Damage = {
129	  itemType: string;
130	  amount: number;
131	};
132	
133	export type ClaimInput = {
134	  items: Item[];
135	  remainingCap: number;
136	  damages: Damage[];
137	};
138	
139	export type ClaimResult = {
140	  payout: number;
141	  remainingCap: number;
142	};
143	
144	function payoutForDamage(damage: Damage, items: Item[]): number {
145	  const item = items.find((i) => i.type === damage.itemType);
146	  const isHighEnchantmentDamage =
147	    item !== undefined && isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_DAMAGE_THRESHOLD);
148	  const reimbursement = isHighEnchantmentDamage
149	    ? damage.amount * HIGH_ENCHANTMENT_DAMAGE_REIMBURSEMENT_RATE
150	    : damage.amount;
151	  return reimbursement - DEDUCTIBLE;
152	}
153	
154	export function claim(input: ClaimInput): ClaimResult {
155	  const totalPayout = input.damages.reduce(
156	    (sum, damage) => sum + payoutForDamage(damage, input.items),
157	    0,
158	  );
159	  return { payout: Math.floor(totalPayout), remainingCap: input.remainingCap };
160	}
161	
162	export function insuranceSum(items: Item[]): number {
163	  return sumByType(items, INSURANCE_VALUE_BY_TYPE);
164	}
165	
166	export function quote(input: QuoteInput): number {
167	  let premium = premiumForItems(input.items);
168	  const baseTotal = baseTotalForItems(input.items);
169	  if (qualifiesForFirstInsuranceSurcharge(input)) {
170	    premium += baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
171	  }
172	  if (qualifiesForLoyaltyDiscount(input)) {
173	    premium -= baseTotal * LOYALTY_DISCOUNT_RATE;
174	  }
175	  if (qualifiesForFollowupDiscount(input)) {
176	    premium -= baseTotal * FOLLOWUP_DISCOUNT_RATE;
177	  }
178	  return Math.ceil(premium + PROCESSING_FEE);
179	}
